prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT (COUNT(DISTINCT ?participant) AS ?participantCount) ?modelId WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId ?modelId .
  FILTER(?modelId = "f404135647444aedabe98bb54c000517")

  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .
  ?defs tai:belongsTo ?model .

  ?participant a bboExt:Participant ;
               tai:belongsTo ?choreo .
}
GROUP BY ?modelId

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?modelId ?modelName (COUNT(DISTINCT ?participant) AS ?participantCount) WHERE {
  ?model a bboExt:Model ;
         bbo:name ?modelName .
  OPTIONAL { ?model tai:normalizedId ?modelId . }
  OPTIONAL { ?model tai:originalId ?origId . }
  FILTER( (?modelId = "f404135647444aedabe98bb54c000517") || (?origId = "f404135647444aedabe98bb54c000517") )

  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .

  { ?participant a bboExt:Participant ; tai:belongsTo ?choreo . }
  UNION
  { ?task a bboExt:ChoreographyTask ; tai:belongsTo ?choreo ;
          bboExt:initiatingParticipantRef ?pRef .
    ?participant a bboExt:Participant ; tai:belongsTo ?choreo ;
          bbo:id ?pRef .
  }
}
GROUP BY ?modelId ?modelName
